html:
{#-
  Sales Invoice Pick List — branded picker-friendly sheet.
  Brand logo is looked up from the ERPNext Brand whose name matches the
  Sales Invoice cost center (with the company-abbreviation suffix stripped,
  e.g. "Ahuhu - KPG" → Brand "Ahuhu").
-#}
{%- set cc_clean = (doc.cost_center or '').rsplit(' - ', 1)[0] | trim -%}
{%- set brand_row = frappe.db.get_value('Brand', cc_clean, ['name', 'image'], as_dict=True) if cc_clean else None -%}
{%- set brand_logo = brand_row.image if brand_row else None -%}
{%- set brand_name = brand_row.name if brand_row else (cc_clean or doc.company) -%}

<style>
  @page { margin: 12mm 14mm; }
  body { font-family: system-ui, -apple-system, "Segoe UI", Arial, sans-serif; color: #1f2937; font-size: 12px; }
  .pl-head { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 16px; }
  .pl-head .brand img { max-height: 60px; max-width: 220px; object-fit: contain; }
  .pl-head .brand .brand-name { font-size: 18px; font-weight: 700; color: #111827; }
  .pl-head .title { text-align: right; }
  .pl-head .title h1 { margin: 0; font-size: 26px; font-weight: 800; letter-spacing: 2px; color: #111827; }
  .pl-head .title .sub { font-size: 11px; color: #6b7280; margin-top: 2px; letter-spacing: 0.5px; }
  .rule { border: 0; border-top: 2px solid #111827; margin: 6px 0 14px; }

  .meta-grid { display: grid; grid-template-columns: 1fr 1fr 1fr 1fr; gap: 4px 18px; margin-bottom: 14px; }
  .meta .lbl { font-size: 9px; font-weight: 700; text-transform: uppercase; letter-spacing: 1px; color: #9ca3af; margin-bottom: 2px; }
  .meta .val { font-size: 12px; color: #111827; font-weight: 600; }

  table.items { border-collapse: collapse; width: 100%; }
  table.items thead th { background: #111827; color: #fff; text-align: left; padding: 9px 10px; font-size: 10px; text-transform: uppercase; letter-spacing: 0.5px; font-weight: 700; }
  table.items thead th.num { text-align: right; }
  table.items thead th.ctr { text-align: center; }
  table.items tbody td { padding: 10px; border-bottom: 1px solid #e5e7eb; font-size: 12px; vertical-align: middle; }
  table.items tbody td.num { text-align: right; }
  table.items tbody td.ctr { text-align: center; }
  table.items .idx { color: #9ca3af; width: 28px; }
  table.items .sku { font-weight: 700; color: #111827; font-size: 13px; }
  table.items .name { color: #4b5563; font-size: 11px; margin-top: 2px; }
  table.items .bc { font-family: "Courier New", monospace; font-size: 11px; color: #111827; background: #f3f4f6; padding: 2px 6px; border-radius: 3px; letter-spacing: 1px; display: inline-block; }
  table.items .qty-big { font-size: 18px; font-weight: 800; color: #111827; }
  table.items .pick-box { display: inline-block; width: 18px; height: 18px; border: 2px solid #9ca3af; border-radius: 3px; vertical-align: middle; }
  table.items tbody tr:nth-child(even) td { background: #fafafa; }

  .footer-sig { margin-top: 22px; display: grid; grid-template-columns: 1fr 1fr; gap: 28px; }
  .sig-box { font-size: 11px; color: #6b7280; }
  .sig-box .line { border-bottom: 1px solid #9ca3af; height: 28px; margin-bottom: 4px; }
  .sig-box .lbl { font-size: 9px; font-weight: 700; text-transform: uppercase; letter-spacing: 1px; color: #9ca3af; }

  .footer { margin-top: 18px; padding-top: 10px; border-top: 1px solid #e5e7eb; font-size: 10px; color: #9ca3af; text-align: center; }
</style>

<div class="pl-head">
  <div class="brand">
    {% if brand_logo %}
      <img src="{{ brand_logo }}" alt="{{ brand_name }}">
    {% else %}
      <div class="brand-name">{{ brand_name }}</div>
    {% endif %}
  </div>
  <div class="title">
    <h1>PICK LIST</h1>
    <div class="sub">Invoice {{ doc.name }}</div>
  </div>
</div>
<hr class="rule">

<div class="meta-grid">
  <div class="meta">
    <div class="lbl">Customer</div>
    <div class="val">{{ doc.customer_name or doc.customer }}</div>
  </div>
  <div class="meta">
    <div class="lbl">Invoice Date</div>
    <div class="val">{{ frappe.utils.formatdate(doc.posting_date) }}</div>
  </div>
  <div class="meta">
    <div class="lbl">Total Lines</div>
    <div class="val">{{ doc.items | length }}</div>
  </div>
  <div class="meta">
    <div class="lbl">Total Qty</div>
    <div class="val">{{ doc.total_qty or (doc.items | sum(attribute='qty')) }}</div>
  </div>
</div>

<table class="items">
  <thead>
    <tr>
      <th class="idx">#</th>
      <th class="ctr" style="width:36px">&#10003;</th>
      <th>Item Code &amp; Name</th>
      <th>Barcode</th>
      <th class="num">Qty</th>
      <th>UOM</th>
      <th>Warehouse</th>
    </tr>
  </thead>
  <tbody>
    {% for item in doc.items %}
    {%- set barcodes = frappe.db.get_all('Item Barcode', filters={'parent': item.item_code}, fields=['barcode'], order_by='idx asc', limit=1) -%}
    {%- set bc = barcodes[0].barcode if barcodes else item.item_code -%}
    <tr>
      <td class="idx">{{ loop.index }}</td>
      <td class="ctr"><span class="pick-box"></span></td>
      <td>
        <div class="sku">{{ item.item_code }}</div>
        {% if item.item_name and item.item_name != item.item_code %}
          <div class="name">{{ item.item_name }}</div>
        {% endif %}
      </td>
      <td><span class="bc">{{ bc }}</span></td>
      <td class="num"><span class="qty-big">{{ item.qty }}</span></td>
      <td>{{ item.uom or 'Nos' }}</td>
      <td style="font-size:11px;color:#6b7280">{{ item.warehouse or '' }}</td>
    </tr>
    {% endfor %}
  </tbody>
</table>

<div class="footer-sig">
  <div class="sig-box">
    <div class="line"></div>
    <div class="lbl">Picked By &middot; Signature &amp; Date</div>
  </div>
  <div class="sig-box">
    <div class="line"></div>
    <div class="lbl">Checked By &middot; Signature &amp; Date</div>
  </div>
</div>

<div class="footer">
  {{ brand_name }} &nbsp;&middot;&nbsp; Pick List for {{ doc.name }} &nbsp;&middot;&nbsp; Printed {{ frappe.utils.format_datetime(frappe.utils.now()) }}
</div>
